old='''function getWhatILike(user = {}) {\n  const v = user.whatILike || {};\n  return {\n    dietary: v.dietary || v.allergies || "",\n    restaurants: v.restaurants || "",\n    drinks: v.drinks || "",\n    shops: v.shops || "",\n    snacks: v.snacks || "",\n    candle: v.candle || "",\n    flower: v.flower || "",\n    color: v.color || "",\n    team: v.team || "",\n    special: v.special || ""\n  };\n}\n\nfunction collectWhatILike(form) {\n  return {\n    dietary: form.likeDietary?.value?.trim() || "",\n    restaurants: form.likeRestaurants?.value?.trim() || "",\n    drinks: form.likeDrinks?.value?.trim() || "",\n    shops: form.likeShops?.value?.trim() || "",\n    snacks: form.likeSnacks?.value?.trim() || "",\n    candle: form.likeCandle?.value?.trim() || "",\n    flower: form.likeFlower?.value?.trim() || "",\n    color: form.likeColor?.value?.trim() || "",\n    team: form.likeTeam?.value?.trim() || "",\n    special: form.likeSpecial?.value?.trim() || ""\n  };\n}\n\nfunction renderWhatILikeFields(user = {}) {\n  const v = getWhatILike(user);\n  return `<div class="what-i-like-editor">\n    <label>Special Dietary Restrictions or Allergies <input name="likeDietary" value="${escapeHtml(v.dietary)}" /></label>\n    <div class="grid two">\n      <label>Favorite Restaurants / Places to Eat <textarea name="likeRestaurants" rows="3">${escapeHtml(v.restaurants)}</textarea></label>\n      <label>Favorite Drinks <textarea name="likeDrinks" rows="3">${escapeHtml(v.drinks)}</textarea></label>\n      <label>Favorite Places to Shop <textarea name="likeShops" rows="3">${escapeHtml(v.shops)}</textarea></label>\n      <label>Favorite Snacks / Candy / Treats <textarea name="likeSnacks" rows="3">${escapeHtml(v.snacks)}</textarea></label>\n      <label>Favorite Candle Smell <input name="likeCandle" value="${escapeHtml(v.candle)}" /></label>\n      <label>Favorite Flower <input name="likeFlower" value="${escapeHtml(v.flower)}" /></label>\n      <label>Favorite Color <input name="likeColor" value="${escapeHtml(v.color)}" /></label>\n      <label>Favorite Team <input name="likeTeam" value="${escapeHtml(v.team)}" /></label>\n    </div>\n    <label>Something Special About Me <textarea name="likeSpecial" rows="4">${escapeHtml(v.special)}</textarea></label>\n  </div>`;\n}\n\nfunction renderWhatILikeDisplay(user = {}, compact = false) {\n  const v = getWhatILike(user);\n  const items = [\n    ["Dietary / Allergies", v.dietary], ["Restaurants", v.restaurants], ["Drinks", v.drinks],\n    ["Places to Shop", v.shops], ["Snacks / Treats", v.snacks], ["Candle", v.candle],\n    ["Flower", v.flower], ["Color", v.color], ["Team", v.team], ["Special About Me", v.special]\n  ].filter(([, value]) => String(value || "").trim());\n  if (!items.length) return `<p class="helper">No favorites have been added yet.</p>`;\n  return `<div class="likes-grid ${compact ? "compact-likes-grid" : ""}">${items.map(([label, value]) => `<div class="like-tile"><small>${escapeHtml(label)}</small><strong>${escapeHtml(value)}</strong></div>`).join("")}</div>`;\n}\n'''
new='''const WHAT_I_LIKE_FIELDS = [\n  ["dietary", "Special Dietary Restrictions or Allergies"],\n  ["restaurants", "Favorite Restaurants / Places to Eat"],\n  ["drinks", "Favorite Drinks"],\n  ["shops", "Favorite Places to Shop"],\n  ["snacks", "Favorite Snacks / Candy / Treats"],\n  ["candle", "Favorite Candle Smell"],\n  ["flower", "Favorite Flower"],\n  ["color", "Favorite Color"],\n  ["team", "Favorite Team"],\n  ["special", "Something Special About Me"]\n];\n\nfunction normalizeLikeList(value) {\n  if (Array.isArray(value)) return value.map(v => String(v || "").trim()).filter(Boolean);\n  return String(value || "").split(/\\n|;/).map(v => v.trim()).filter(Boolean);\n}\n\nfunction getWhatILike(user = {}) {\n  const v = user.whatILike || {};\n  const out = {};\n  WHAT_I_LIKE_FIELDS.forEach(([key]) => { out[key] = normalizeLikeList(key === "dietary" ? (v.dietary || v.allergies || "") : v[key]); });\n  return out;\n}\n\nfunction collectLikeList(form, key) {\n  const modern = Array.from(form.querySelectorAll(`[name="like_${key}"]`)).map(i => i.value.trim()).filter(Boolean);\n  if (modern.length) return modern;\n  const legacyName = "like" + key.charAt(0).toUpperCase() + key.slice(1);\n  return normalizeLikeList(form[legacyName]?.value || "");\n}\n\nfunction collectWhatILike(form) {\n  const out = {};\n  WHAT_I_LIKE_FIELDS.forEach(([key]) => { out[key] = collectLikeList(form, key); });\n  return out;\n}\n\nfunction renderLikeRows(key, values = []) {\n  const rows = values.length ? values : [""];\n  return rows.map((value, idx) => `<div class="like-entry-row" data-like-row>\n    <input name="like_${key}" value="${escapeHtml(value)}" placeholder="Add one item..." />\n    ${idx === rows.length - 1 ? `<button type="button" class="secondary small like-add-button" data-add-like-row="${key}">+</button>` : `<button type="button" class="secondary small" data-remove-like-row>−</button>`}\n  </div>`).join("");\n}\n\nfunction renderWhatILikeFields(user = {}) {\n  const v = getWhatILike(user);\n  return `<div class="what-i-like-editor dynamic-likes-editor">\n    <p class="helper">Add as many favorites as you want. Once you type one, press + to add another.</p>\n    <div class="likes-editor-grid">\n      ${WHAT_I_LIKE_FIELDS.map(([key, label]) => `<section class="like-editor-card" data-like-group="${key}">\n        <h4>${escapeHtml(label)}</h4>\n        <div data-like-rows="${key}">${renderLikeRows(key, v[key])}</div>\n      </section>`).join("")}\n    </div>\n  </div>`;\n}\n\nfunction renderWhatILikeDisplay(user = {}, compact = false) {\n  const v = getWhatILike(user);\n  const items = WHAT_I_LIKE_FIELDS.map(([key, label]) => [label, v[key]]).filter(([, value]) => Array.isArray(value) && value.length);\n  if (!items.length) return `<p class="helper">No favorites have been added yet.</p>`;\n  return `<div class="likes-grid ${compact ? "compact-likes-grid" : ""}">${items.map(([label, values]) => `<div class="like-tile"><small>${escapeHtml(label)}</small><strong>${values.map(value => `<span>${escapeHtml(value)}</span>`).join("")}</strong></div>`).join("")}</div>`;\n}\n'''
