old3='''  const school = state.schools.find(s => s.id === schoolId);\n  const grouped = state.positions.map(pos => ({ position: pos.name, people: users.filter(u => u.teamPosition === pos.name) })).filter(g => g.people.length);\n  const loose = users.filter(u => !u.teamPosition || !state.positions.some(p => p.name === u.teamPosition));\n  if (loose.length) grouped.push({ position: "Other Team Members", people: loose });\n  $app.innerHTML = `<main class="shell public-share-shell">\n    <section class="card public-share-hero"><p class="eyebrow">Oak Village Academy</p><h1>Meet Our Teachers</h1><p class="helper">${escapeHtml(school?.name || "Select a position to find a teacher and see the things they like.")}</p></section>\n    <section class="public-position-list">\n      ${grouped.length ? grouped.map(g => `<details class="card public-position-card"><summary><strong>${escapeHtml(g.position)}</strong><span>${g.people.length} team member${g.people.length === 1 ? "" : "s"}</span></summary><div class="public-teacher-list">${g.people.map(u => `<details class="public-teacher-card"><summary>${u.profileImageData ? `<img src="${u.profileImageData}" alt="" />` : `<b>${escapeHtml((u.firstName || "?").slice(0,1))}</b>`}<span><strong>${escapeHtml(getUserUsedName(u))}</strong><small>${escapeHtml(u.teamPosition || "")}</small></span></summary><div class="public-likes-page">${renderWhatILikeDisplay(u, true)}</div></details>`).join("")}</div></details>`).join("") : `<div class="card empty">No teacher information is available yet.</div>`}\n    </section>\n  </main>`;\n}\n'''
